SELECT * FROM food_post

  status=1

    AND area_code=#{areaCode}


    AND category = #{category}


    AND create_time < #{cursor}


ORDER BY create_time DESC
LIMIT #{size}

SELECT * FROM food_post
WHERE user_id = #{userId}
  AND status IN (1, 2)

  AND create_time < #{cursor}

ORDER BY create_time DESC
LIMIT #{size}
